#!/usr/bin/env python3
"""Materialize the frozen STLM L1-D2 corpora from compact deterministic fixtures."""

from __future__ import annotations

import argparse
import base64
import gzip
import hashlib
from pathlib import Path

SURFACE_SHA256 = "30e12242e33f70c38abec5a069d6ed856170f7bbdcc896ca396e56139b591b6c"
INVALID_SHA256 = "419b20e48f1b6e02621639850c667ef1b2d2b5ef5807a7cbbe49a2bd91803912"
SURFACE_GZIP_BASE64 = ""
INVALID_GZIP_BASE64 = ""


def parse_args() -> argparse.Namespace:
    parser = argparse.ArgumentParser()
    parser.add_argument("--output-dir", type=Path, default=Path("tools/stlm_l1d/data"))
    return parser.parse_args()


def materialize(encoded: str, expected_sha256: str, output: Path) -> None:
    payload = gzip.decompress(base64.b64decode(encoded))
    observed = hashlib.sha256(payload).hexdigest()
    if observed != expected_sha256:
        raise ValueError(f"{output}: {observed} != {expected_sha256}")
    output.parent.mkdir(parents=True, exist_ok=True)
    output.write_bytes(payload)


def main() -> None:
    args = parse_args()
    surface = args.output_dir / "valid_surface_tournaments.jsonl"
    invalid = args.output_dir / "semantic_invalid_candidates.jsonl"
    materialize(SURFACE_GZIP_BASE64, SURFACE_SHA256, surface)
    materialize(INVALID_GZIP_BASE64, INVALID_SHA256, invalid)
    print(f"materialized {surface} and {invalid}")


if __name__ == "__main__":
    main()
